对内部循环进行4路展开，减少循环开销和分支预测失败。

// 前向扫描优化示例
for (int j=0; j< currentNumberOfNonzeros-3; j+=4) {
    local_int_t curCol1 = currentColIndices[j];
    local_int_t curCol2 = currentColIndices[j+1];
    local_int_t curCol3 = currentColIndices[j+2];
    local_int_t curCol4 = currentColIndices[j+3];
    sum -= currentValues[j] * xv[curCol1];
    sum -= currentValues[j+1] * xv[curCol2];
    sum -= currentValues[j+3] * xv[curCol3];
    sum -= currentValues[j+4] * xv[curCol4];
}
// 处理剩余元素

1. 对currentColIndices和currentValues数组进行预取
2. 重新组织数据结构，将矩阵值按缓存行对齐存储
3. 使用__builtin_prefetch进行显式预取

// 在循环开始前预取
__builtin_prefetch(currentColIndices + 64, 0, 0);
__builtin_prefetch(currentValues + 64, 0, 0);
// 在循环内部定期预取
if (j % 16 == 0) {
    __builtin_prefetch(currentColIndices + j + 64, 0, 0);
    __builtin_prefetch(currentValues + j + 64, 0, 0);
}

