1. 使用单精度存储矩阵值，双精度进行累加
2. 对currentValues使用float类型
3. 在累加时转换为double

// 修改矩阵存储为单精度
const float * const currentValues = A.matrixValues[i];
// 在计算时转换
double sum = rv[i];
for (int j=0; j< currentNumberOfNonzeros; j++) {
    local_int_t curCol = currentColIndices[j];
    sum -= (double)currentValues[j] * xv[curCol];
